/* ====================================================================
   NIMBUS · Aurora Glass  —  shared helpers (template-level CSS)
   --------------------------------------------------------------------
   NOTE: the layout-template CSS sanitizer strips CSS custom properties
   (--x), @keyframes, @media, backdrop-filter and vendor-prefixed props.
   So every value here is inlined, and colors are built from the live
   MudBlazor palette via rgba(var(--mud-palette-*-rgb), a) — which DOES
   survive — so all surfaces still auto-adapt to light / dark mode.
   ==================================================================== */

/* Distinctive brand wordmark (system fonts only — external fonts are stripped) */
.nb-wordmark {
    font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
    font-weight: 800;
    letter-spacing: 0.16em;
    text-transform: uppercase;
}

/* Gradient logo "chip" — stands in for a logo image everywhere one would go */
.nb-mark {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background:
        linear-gradient(135deg, rgba(255,255,255,0.18), rgba(255,255,255,0) 55%),
        linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb),1) 0%, rgba(var(--mud-palette-secondary-rgb),1) 100%);
    color: rgba(255,255,255,1);
    border-radius: 12px;
    box-shadow: 0 12px 30px -10px rgba(var(--mud-palette-primary-rgb),0.6);
    flex: none;
}
.nb-mark i { line-height: 1; }

/* Status dot used in the login footer + account block */
.nb-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; flex: none; }
.nb-dot--ok { background: rgba(52,211,153,1); box-shadow: 0 0 0 4px rgba(52,211,153,0.18); }

/* Motion (full-trust only — @keyframes survive raw CSS) */
@keyframes nb-aurora-drift {
    0%   { transform: translate3d(0, 0, 0) scale(1); }
    50%  { transform: translate3d(2%, -1.5%, 0) scale(1.07); }
    100% { transform: translate3d(0, 0, 0) scale(1); }
}
@keyframes nb-rise {
    from { opacity: 0; transform: translateY(16px); }
    to   { opacity: 1; transform: translateY(0); }
}
@media (prefers-reduced-motion: reduce) {
    .auth-bg-image, .nb-login__card { animation: none !important; }
}

