{% comment %}
  Recreation of the built-in game service home page. Same layout, same permission gating —
  edit freely from here. Tokens self-gate on the viewer's permissions; the {% if Permissions.* %}
  wrappers additionally remove the empty grid slots, exactly like the built-in page does.
{% endcomment %}
<div class="mud-grid mud-grid-spacing-xs-2 justify-start">
  <div class="mud-grid-item mud-grid-item-xs-12 gsh-alert">{% component "game-status-alert" %}</div>
  <div class="mud-grid-item mud-grid-item-xs-12">
    <div class="mud-grid mud-grid-spacing-xs-2 justify-start">
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "service-uptime-tile" %}
      </div>
      {% if Permissions.PlayerStats %}
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "game-players-tile" %}
      </div>
      {% endif %}
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "service-disk-tile" %}
      </div>
      {% if Permissions.CpuStats %}
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "service-cpu-tile" %}
      </div>
      {% endif %}
      {% if Permissions.MemoryStats %}
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "service-memory-tile" %}
      </div>
      {% endif %}
      {% if Permissions.NetworkStats %}
      <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-sm-12 mud-grid-item-md-6 mud-grid-item-lg-2 mb-2">
        {% component "game-network-tile" %}
      </div>
      {% endif %}
    </div>
  </div>
  <div class="mud-grid-item mud-grid-item-xs-12{% if Permissions.Logs or Permissions.ServiceActivity %} mud-grid-item-lg-8 mud-grid-item-xl-9{% endif %}">
    <div class="mud-tabs mud-height-full gsh-tabs">
      {% if Permissions.Console %}<input type="radio" name="gsh-tab" id="gsh-t-console" class="gsh-tin" checked>{% endif %}
      <input type="radio" name="gsh-tab" id="gsh-t-details" class="gsh-tin"{% unless Permissions.Console %} checked{% endunless %}>
      <input type="radio" name="gsh-tab" id="gsh-t-advanced" class="gsh-tin">
      <div class="mud-tabs-tabbar rounded mb-2">
        <div class="mud-tabs-tabbar-inner">
          <div class="mud-tabs-tabbar-content">
            <div class="mud-tabs-tabbar-wrapper">
              {% if Permissions.Console %}
              <div class="mud-tooltip-root mud-tooltip-inline"><label for="gsh-t-console" class="mud-tab mud-ripple mud-tab-panel">
                <svg class="mud-icon-root mud-svg-icon mud-icon-size-medium mud-tab-icon-text" viewBox="0 0 24 24" focusable="false" aria-hidden="true"><path d="M20,4H4C2.89,4,2,4.9,2,6v12c0,1.1,0.89,2,2,2h16c1.1,0,2-0.9,2-2V6C22,4.9,21.11,4,20,4z M20,18H4V8h16V18z M18,17h-6v-2 h6V17z M7.5,17l-1.41-1.41L8.67,13l-2.59-2.59L7.5,9l4,4L7.5,17z"/></svg>
                Console
              </label></div>
              {% endif %}
              <div class="mud-tooltip-root mud-tooltip-inline"><label for="gsh-t-details" class="mud-tab mud-ripple mud-tab-panel">
                <svg class="mud-icon-root mud-svg-icon mud-icon-size-medium mud-tab-icon-text" viewBox="0 0 24 24" focusable="false" aria-hidden="true"><path d="M0 0h24v24H0z" fill="none"/><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
                Service Details
              </label></div>
              <div class="mud-tooltip-root mud-tooltip-inline"><label for="gsh-t-advanced" class="mud-tab mud-ripple mud-tab-panel">
                <svg class="mud-icon-root mud-svg-icon mud-icon-size-medium mud-tab-icon-text" viewBox="0 0 24 24" focusable="false" aria-hidden="true"><path d="M0,0h24v24H0V0z" fill="none"/><path d="M19.14,12.94c0.04-0.3,0.06-0.61,0.06-0.94c0-0.32-0.02-0.64-0.07-0.94l2.03-1.58c0.18-0.14,0.23-0.41,0.12-0.61 l-1.92-3.32c-0.12-0.22-0.37-0.29-0.59-0.22l-2.39,0.96c-0.5-0.38-1.03-0.7-1.62-0.94L14.4,2.81c-0.04-0.24-0.24-0.41-0.48-0.41 h-3.84c-0.24,0-0.43,0.17-0.47,0.41L9.25,5.35C8.66,5.59,8.12,5.92,7.63,6.29L5.24,5.33c-0.22-0.08-0.47,0-0.59,0.22L2.74,8.87 C2.62,9.08,2.66,9.34,2.86,9.48l2.03,1.58C4.84,11.36,4.8,11.69,4.8,12s0.02,0.64,0.07,0.94l-2.03,1.58 c-0.18,0.14-0.23,0.41-0.12,0.61l1.92,3.32c0.12,0.22,0.37,0.29,0.59,0.22l2.39-0.96c0.5,0.38,1.03,0.7,1.62,0.94l0.36,2.54 c0.05,0.24,0.24,0.41,0.48,0.41h3.84c0.24,0,0.44-0.17,0.47-0.41l0.36-2.54c0.59-0.24,1.13-0.56,1.62-0.94l2.39,0.96 c0.22,0.08,0.47,0,0.59-0.22l1.92-3.32c0.12-0.22,0.07-0.47-0.12-0.61L19.14,12.94z M12,15.6c-1.98,0-3.6-1.62-3.6-3.6 s1.62-3.6,3.6-3.6s3.6,1.62,3.6,3.6S13.98,15.6,12,15.6z"/></svg>
                Advanced Options
              </label></div>
            </div>
          </div>
        </div>
      </div>
      <div class="mud-tabs-panels mud-height-full">
        {% if Permissions.Console %}<div class="gsh-panel gsh-p-console">{% component "game-console" %}</div>{% endif %}
        <div class="gsh-panel gsh-p-details">{% component "service-details" %}</div>
        <div class="gsh-panel gsh-p-advanced">{% component "service-advanced-actions" %}</div>
      </div>
    </div>
  </div>
  {% if Permissions.Logs or Permissions.ServiceActivity %}
  <div class="mud-grid-item mud-grid-item-xs-12 mud-grid-item-lg-4 mud-grid-item-xl-3 gsh-side" style="height: 600px">
    <div class="mud-grid mud-grid-spacing-xs-2 justify-start">
      {% if Permissions.Logs %}
      <div class="mud-grid-item mud-grid-item-xs-12">{% component "service-recent-logs" %}</div>
      {% endif %}
      {% if Permissions.ServiceActivity %}
      <div class="mud-grid-item mud-grid-item-xs-12">{% component "service-recent-activity" %}</div>
      {% endif %}
    </div>
  </div>
  {% endif %}
</div>

contents.css:
/* CSS-only tabs: the radios drive which panel shows (active panel uses display:contents,
   exactly what MudTabs renders) and which label gets the active color + underline. */
.gsh-tin{display:none}
.gsh-alert:empty{display:none}
.gsh-tabs label.mud-tab{cursor:pointer}
.gsh-panel{display:none}
#gsh-t-console:checked ~ .mud-tabs-panels > .gsh-p-console{display:contents}
#gsh-t-details:checked ~ .mud-tabs-panels > .gsh-p-details{display:contents}
#gsh-t-advanced:checked ~ .mud-tabs-panels > .gsh-p-advanced{display:contents}
#gsh-t-console:checked ~ .mud-tabs-tabbar label[for="gsh-t-console"],
#gsh-t-details:checked ~ .mud-tabs-tabbar label[for="gsh-t-details"],
#gsh-t-advanced:checked ~ .mud-tabs-tabbar label[for="gsh-t-advanced"]{color:var(--mud-palette-primary);box-shadow:inset 0 -2px 0 var(--mud-palette-primary)}
/* The built-in page hides the logs/activity column on phones/tablets (MudHidden SmAndDown). */
@media (max-width: 959.98px){.gsh-side{display:none}}

/* ============ NIMBUS · LoginPage surface ============ */

/* Replace AuthLayout's photographic background with a layered aurora (gradients survive sanitizing) */
.auth-bg-image {
    background-image:
        radial-gradient(60% 80% at 16% 8%,   rgba(var(--mud-palette-primary-rgb),   0.60), transparent 60%),
        radial-gradient(55% 75% at 88% 14%,  rgba(var(--mud-palette-secondary-rgb), 0.52), transparent 60%),
        radial-gradient(85% 85% at 60% 108%, rgba(var(--mud-palette-tertiary-rgb),  0.50), transparent 62%) !important;
    background-color: var(--mud-palette-background) !important;
    background-size: 185% 185% !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    filter: saturate(1.18);
    animation: nb-aurora-drift 26s ease-in-out infinite;
}
/* Soften the flat overlay into a top-down vignette so the card pops */
.auth-bg-overlay {
    background: radial-gradient(130% 110% at 50% -10%, transparent 42%, rgba(0,0,0,0.42)) !important;
    opacity: 1 !important;
}

/* Corner theme toggle → frosted pill */
.auth-theme-toggle .mud-icon-button {
    background: rgba(var(--mud-palette-surface-rgb), 0.45);
    backdrop-filter: blur(14px) saturate(1.3);
    -webkit-backdrop-filter: blur(14px) saturate(1.3);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.30);
    border-radius: 999px;
}

/* ---- Card ---- */
.nb-login { position: relative; width: 100%; display: flex; justify-content: center; }
.nb-login__announce { position: absolute; bottom: calc(100% + 18px); width: 100%; max-width: 430px; }

.nb-login__card {
    width: 430px;
    max-width: 92vw;
    padding: 40px 36px 24px;
    border-radius: 24px;
    background:
        linear-gradient(180deg, rgba(255,255,255,0.10), rgba(255,255,255,0) 40%),
        rgba(var(--mud-palette-surface-rgb), 0.55);
    backdrop-filter: blur(28px) saturate(1.4);
    -webkit-backdrop-filter: blur(28px) saturate(1.4);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.32);
    box-shadow:
        0 30px 80px -22px rgba(0,0,0,0.62),
        inset 0 1px 0 rgba(255,255,255,0.16);
    animation: nb-rise 0.6s cubic-bezier(0.2, 0.7, 0.2, 1) both;
}

/* ---- Brand ---- */
.nb-login__brand { display: flex; align-items: center; gap: 15px; margin-bottom: 22px; }
.nb-login__mark { width: 56px; height: 56px; font-size: 27px; border-radius: 16px; }
.nb-login__id { display: flex; flex-direction: column; }
.nb-login__name {
    margin: 0;
    font-size: 30px;
    line-height: 1;
    color: var(--mud-palette-text-primary);
}
.nb-login__tag {
    margin: 5px 0 0;
    font-size: 11px;
    letter-spacing: 0.24em;
    text-transform: uppercase;
    color: rgba(var(--mud-palette-secondary-rgb), 1);
}

/* ---- "Welcome back" divider ---- */
.nb-login__divider { display: flex; align-items: center; gap: 12px; margin: 4px 0 22px; }
.nb-login__divider-line { flex: 1; height: 1px; background: linear-gradient(90deg, transparent, rgba(var(--mud-palette-primary-rgb), 0.4), transparent); }
.nb-login__divider-text {
    font-size: 11px;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--mud-palette-text-secondary);
}

/* ---- Form fields → frosted ---- */
.nb-login .login-field .mud-input-outlined {
    background: rgba(var(--mud-palette-surface-rgb), 0.38);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border-radius: 12px;
}
.nb-login .login-field .mud-input-outlined-border { border-color: rgba(var(--mud-palette-primary-rgb), 0.30); border-radius: 12px; transition: border-color .15s ease, box-shadow .15s ease; }
.nb-login .login-field .mud-input-outlined:focus-within .mud-input-outlined-border {
    border-color: rgba(var(--mud-palette-primary-rgb), 1) !important;
    border-width: 1px !important;
    box-shadow: 0 0 0 3px rgba(var(--mud-palette-primary-rgb), 0.20);
}

/* ---- Submit button → gradient + glow ---- */
.nb-login .login-submit-btn {
    background: linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb),1) 0%, rgba(var(--mud-palette-secondary-rgb),1) 100%) !important;
    color: rgba(255,255,255,1) !important;
    border: 0 !important;
    border-radius: 12px;
    height: 48px;
    margin-top: 4px;
    font-weight: 700;
    letter-spacing: 0.05em;
    box-shadow: 0 12px 38px -10px rgba(var(--mud-palette-primary-rgb), 0.6);
    transition: filter .15s ease, box-shadow .2s ease, transform .1s ease;
}
.nb-login .login-submit-btn:hover {
    filter: brightness(1.08);
    box-shadow: 0 18px 50px -10px rgba(var(--mud-palette-primary-rgb), 0.72);
}
.nb-login .login-submit-btn:active { transform: translateY(1px); }
.nb-login .login-forgot-btn { font-size: 12px; letter-spacing: 0.02em; }

/* ---- Footer row ---- */
.nb-login__foot {
    display: flex;
    align-items: center;
    gap: 9px;
    margin-top: 20px;
    padding-top: 16px;
    border-top: 1px solid rgba(var(--mud-palette-primary-rgb), 0.22);
}
.nb-login__foot-text { font-size: 12px; color: var(--mud-palette-text-secondary); }
.nb-login__lang { margin-left: auto; }
.nb-login__lang .mud-input-control { margin: 0; }

/* Tidy AuthLayout's own copyright footer */
.auth-footer { color: var(--mud-palette-text-secondary); opacity: 0.7; letter-spacing: 0.04em; }

/* ============ NIMBUS · Shell surface (authenticated chrome) ============
   Composed {% component "shell" %} so MudBlazor owns layout coordination.
   Every rule is scoped via :has(.mud-appbar) so none of it leaks onto the
   login page (which shares the .mud-layout wrapper). No backdrop-filter
   (stripped) — translucency + a light top sheen fake the frosted look. */

/* ---- Aurora backdrop behind the translucent chrome ---- */
.mud-layout:has(.mud-appbar) {
    background-color: var(--mud-palette-background) !important;
    background-image:
        radial-gradient(48% 60% at 10% 0%,   rgba(var(--mud-palette-primary-rgb),   0.24), transparent 60%),
        radial-gradient(46% 64% at 99% 4%,    rgba(var(--mud-palette-secondary-rgb), 0.18), transparent 58%),
        radial-gradient(60% 70% at 80% 110%,  rgba(var(--mud-palette-tertiary-rgb),  0.18), transparent 60%) !important;
    background-attachment: fixed !important;
    background-repeat: no-repeat !important;
}
/* Transparent so the aurora backdrop shows through. isolation:isolate makes
   this a stacking context so the game-service hero's z-index:-10 background
   image stays contained ABOVE this opaque backdrop — without it the negative
   z-index escapes to the root stacking context and the .mud-layout
   background-color paints over the image (it only "worked" on the default
   theme because that layout is transparent). */
.mud-layout:has(.mud-appbar) .mud-main-content { background: transparent !important; isolation: isolate; }

/* ---- Top app bar → frosted glass ---- */
.mud-layout:has(.mud-appbar) .mud-appbar {
    background:
        linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0) 70%),
        rgba(var(--mud-palette-surface-rgb), 0.62) !important;
    backdrop-filter: blur(20px) saturate(1.4);
    -webkit-backdrop-filter: blur(20px) saturate(1.4);
    border-bottom: 1px solid rgba(var(--mud-palette-primary-rgb), 0.28);
    box-shadow: 0 8px 30px -16px rgba(0, 0, 0, 0.6);
}

/* ---- Navigation drawer → frosted glass ---- */
.mud-layout:has(.mud-appbar) .mud-drawer {
    background:
        linear-gradient(180deg, rgba(255,255,255,0.05), rgba(255,255,255,0) 30%),
        rgba(var(--mud-palette-surface-rgb), 0.58) !important;
    backdrop-filter: blur(20px) saturate(1.4);
    -webkit-backdrop-filter: blur(20px) saturate(1.4);
    border-right: 1px solid rgba(var(--mud-palette-primary-rgb), 0.24);
}

/* A nav drawer never scrolls horizontally — clip the ~8px the inset nav-link pill margins spill */
.mud-layout:has(.mud-appbar) .mud-drawer-content { overflow-x: hidden; }

/* Nav links: pill hover + a gradient rail on the active item */
.mud-layout:has(.mud-appbar) .mud-nav-link {
    border-radius: 10px;
    margin: 2px 8px;
    transition: background-color .15s ease, color .15s ease;
}
.mud-layout:has(.mud-appbar) .mud-nav-link:hover {
    background: rgba(var(--mud-palette-primary-rgb), 0.10);
}
.mud-layout:has(.mud-appbar) .mud-nav-link.active {
    background: rgba(var(--mud-palette-primary-rgb), 0.16);
    color: rgba(var(--mud-palette-primary-rgb), 1) !important;
    box-shadow: inset 3px 0 0 0 rgba(var(--mud-palette-primary-rgb), 1);
}
.mud-layout:has(.mud-appbar) .mud-nav-link.active .mud-nav-link-icon { color: rgba(var(--mud-palette-primary-rgb), 1) !important; }
.mud-layout:has(.mud-appbar) .mud-nav-group > .mud-nav-link { opacity: 0.92; }

/* Collapsed (mini) rail: the expanded h-margin shifts the icon right and the drawer's
   overflow-x:hidden (note above) clips it — drop it in the closed state so the icon re-centers. */
.mud-layout:has(.mud-appbar) .mud-drawer--closed .mud-nav-link { margin-left: 0; margin-right: 0; }

/* ---- Content cards → translucent (scoped to main content so dialogs /
   popovers / menus, which render outside it, stay fully opaque) ----
   :not([style*="background-image"]) skips papers that set their own inline
   background image (the game/service hero, list-row + grid cards) — otherwise
   this !important background shorthand overpaints their url with the tint.
   :not(.mud-theme-transparent) skips papers that declare themselves invisible
   (e.g. the service power-control wrapper) — tinting those draws a big empty
   card around their content. */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper:not(.mud-table-container):not(.mud-menu-list):not(.mud-list):not(.mud-theme-transparent):not([style*="background-image"]) {
    background:
        linear-gradient(180deg, rgba(255,255,255,0.05), rgba(255,255,255,0) 45%),
        rgba(var(--mud-palette-surface-rgb), 0.60) !important;
    backdrop-filter: blur(16px) saturate(1.25);
    -webkit-backdrop-filter: blur(16px) saturate(1.25);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.18);
    border-radius: 14px !important;
    box-shadow: 0 16px 40px -22px rgba(0, 0, 0, 0.55);
}
/* Inner nested papers stay flat (no double tint / shadow) — but never blank out
   a nested card that carries its own inline background image (e.g. the grid /
   list game cards live inside an outer paper). */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper .mud-paper:not([style*="background-image"]) {
    background: transparent !important;
    box-shadow: none;
    border: 0;
}

/* In-app primary buttons pick up the brand gradient for consistency */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-button-filled-primary {
    background: linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb),1) 0%, rgba(var(--mud-palette-secondary-rgb),1) 100%) !important;
    box-shadow: 0 12px 38px -10px rgba(var(--mud-palette-primary-rgb), 0.55);
    border: 0 !important;
}

/* ============ NIMBUS · Shell.DrawerFooter (account block + our own profile/logout) ============ */

/* Hide the compiled drawer's default Profile + Logout block — we render our own below, on-brand. */
.mud-drawer .mud-navmenu.mt-auto { display: none; }

.nb-df {
    display: flex;
    flex-direction: column;
    gap: 4px;
    margin: auto 12px 14px;   /* margin-top:auto pins the block to the bottom of the flex-column drawer */
    padding: 6px;
    border-radius: 14px;
    background: rgba(var(--mud-palette-primary-rgb), 0.10);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.24);
}

/* Account identity row → links to the profile page */
.nb-df__user {
    display: flex;
    align-items: center;
    gap: 11px;
    padding: 7px 8px;
    border-radius: 10px;
    text-decoration: none;
    color: inherit;
    transition: background-color .15s ease;
}
.nb-df__user:hover { background: rgba(var(--mud-palette-primary-rgb), 0.14); }
.nb-df__avatar {
    width: 34px; height: 34px;
    flex: none;
    display: inline-flex; align-items: center; justify-content: center;
    border-radius: 10px;
    background: rgba(var(--mud-palette-secondary-rgb), 0.20);
    color: rgba(var(--mud-palette-secondary-rgb), 1);
    font-size: 15px;
}
.nb-df__meta { display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
.nb-df__name {
    font-size: 13px; font-weight: 600;
    color: var(--mud-palette-text-primary);
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.nb-df__role {
    font-size: 10px; letter-spacing: 0.16em; text-transform: uppercase;
    color: var(--mud-palette-text-secondary);
}
.nb-df__dot { margin-left: auto; }

/* Logout link — same row style, error-tinted on hover (icon column aligns under the avatar) */
.nb-df__logout {
    display: flex;
    align-items: center;
    gap: 11px;
    padding: 8px;
    border-radius: 10px;
    text-decoration: none;
    color: var(--mud-palette-text-secondary);
    font-size: 13px; font-weight: 600;
    transition: background-color .15s ease, color .15s ease;
}
.nb-df__logout:hover {
    background: rgba(var(--mud-palette-error-rgb), 0.12);
    color: rgba(var(--mud-palette-error-rgb), 1);
}
.nb-df__logout-ico { width: 34px; flex: none; text-align: center; font-size: 15px; }

/* Collapsed (mini) drawer → icons only, centered */
.mud-drawer--closed .nb-df {
    margin: auto 6px 12px;
    padding: 6px;
    background: transparent;
    border: 0;
}
.mud-drawer--closed .nb-df__user { justify-content: center; padding: 6px; }
.mud-drawer--closed .nb-df__logout { justify-content: center; padding: 6px; }
.mud-drawer--closed .nb-df__logout-ico { width: auto; }
.mud-drawer--closed .nb-df__meta,
.mud-drawer--closed .nb-df__dot,
.mud-drawer--closed .nb-df__logout-text { display: none; }

/* ============ NIMBUS · Shell.DrawerHeader (brand zone, above the nav) ============ */
.nb-dh { display: flex; align-items: center; gap: 12px; padding: 18px 16px 14px; }
.nb-dh__mark { width: 40px; height: 40px; font-size: 19px; border-radius: 12px; }
.nb-dh__text { display: flex; flex-direction: column; min-width: 0; overflow: hidden; white-space: nowrap; }
.nb-dh__name { font-size: 19px; line-height: 1; color: var(--mud-palette-text-primary); }
.nb-dh__tag {
    margin-top: 3px;
    font-size: 10px;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: rgba(var(--mud-palette-secondary-rgb), 1);
}

/* Collapsed (mini) drawer → chip only, centered */
.mud-drawer--closed .nb-dh { justify-content: center; padding-left: 0; padding-right: 0; }
.mud-drawer--closed .nb-dh__text { display: none; }

/* ============ NIMBUS · Shell.Footer (replaces the default powered-by bar, 32px tall) ============ */
.nb-ft {
    display: flex;
    align-items: center;
    gap: 10px;
    width: 100%;
    padding: 0 14px;
    font-size: 12px;
    color: var(--mud-palette-text-secondary);
}
.nb-ft__brand { display: inline-flex; align-items: center; gap: 7px; flex: none; }
.nb-ft__bolt { color: rgba(var(--mud-palette-primary-rgb), 1); font-size: 12px; }
.nb-ft__name { font-size: 12px; letter-spacing: 0.16em; color: var(--mud-palette-text-primary); }
.nb-ft__sub { font-size: 10px; letter-spacing: 0.16em; text-transform: uppercase; opacity: 0.8; }

/* The page-driven bottom-bar section (live service stats). Grows to fill the middle; the section's
   own MudSpacer pushes the status text to its right edge. Empty (just a spacer) on non-service pages. */
.nb-ft__resources { flex: 1; display: flex; align-items: center; min-width: 0; overflow: hidden; }

.nb-ft__item { display: inline-flex; align-items: center; gap: 6px; flex: none; }
.nb-ft__ver {
    font-variant-numeric: tabular-nums;
    padding: 2px 9px;
    border-radius: 999px;
    background: rgba(var(--mud-palette-primary-rgb), 0.14);
    opacity: 0.9;
}

/* ============ NIMBUS · Shell.MenuLinks (custom links appended to the nav menu) ============ */
/* The .mud-nav-link anchor inherits native nav styling (padding/hover/mini-collapse) + the
   Shell surface's pill-hover rules. Only the FA icon needs sizing — kept here (not inline) to
   match MudBlazor's 24px nav icons. mud-icon-root is load-bearing for the mini-collapse rail. */
.nb-ml-ico { font-size: 24px; width: 24px; text-align: center; }

/* ============ NIMBUS · Shell.TopBarEnd (status pill, after the dark-mode toggle) ============ */
.nb-te { display: inline-flex; align-items: center; margin-left: 6px; margin-right: 4px; }
.nb-te__pill {
    display: inline-flex;
    align-items: center;
    padding: 4px 10px;
    border-radius: 999px;
    background: rgba(var(--mud-palette-surface-rgb), 0.6);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.28);
}
